import sys

def find_pivot(arr, low, high):
    while low <= high:
        if low == high:
            return low
        mid = (low + high) // 2
        if mid < high and arr[mid] > arr[mid + 1]:
            return mid
        if mid > low and arr[mid] < arr[mid - 1]:
            return mid - 1
        if arr[low] >= arr[mid]:
            high = mid - 1
        else:
            low = mid + 1
    return -1

def binary_search(arr, low, high, key):
    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == key:
            return mid
        if arr[mid] < key:
            low = mid + 1
        else:
            high = mid - 1
    return -1

def search(arr, key):
    n = len(arr)
    pivot = find_pivot(arr, 0, n - 1)
    if pivot == -1:
        return binary_search(arr, 0, n - 1, key)
    if arr[pivot] == key:
        return pivot
    if arr[0] <= key:
        return binary_search(arr, 0, pivot - 1, key)
    return binary_search(arr, pivot + 1, n - 1, key)

